"""
AgentReady — LLM Generator (Phase 3)

Takes the structured analysis JSON produced by analyser.py and uses
an LLM to write each output file from scratch.

Uses LiteLLM — works with Anthropic, OpenAI, and Google providers.
"""

from __future__ import annotations

import json
import random
import time
from datetime import datetime, timezone
from pathlib import Path
from typing import Any

GENERATION_HEADER = (
    "<!-- Generated by AgentReady (LLM-first mode) | "
    "Dynamic section: do not edit manually. "
    "Static section in agent-context.json: safe to edit. -->"
)


# ── Token usage and cost tracking ─────────────────────────────────────────────

_usage_totals: dict = {
    "input_tokens": 0,
    "output_tokens": 0,
    "calls": 0,
    "by_model": {},
}

ANTHROPIC_PRICING: dict = {
    "claude-opus-4-6": {"input": 15.00, "output": 75.00},
    "claude-sonnet-4-6": {"input": 3.00, "output": 15.00},
    "claude-haiku-4-5": {"input": 0.80, "output": 4.00},
    "claude-haiku-4-5-20251001": {"input": 0.80, "output": 4.00},
}


def _calculate_cost(model: str, input_tokens: int, output_tokens: int) -> float:
    pricing = ANTHROPIC_PRICING.get(model, {"input": 0.0, "output": 0.0})
    return (
        input_tokens / 1_000_000 * pricing["input"] + output_tokens / 1_000_000 * pricing["output"]
    )


def get_usage_report() -> dict:
    total_cost = sum(
        _calculate_cost(model, data["input"], data["output"])
        for model, data in _usage_totals.get("by_model", {}).items()
    )
    return {**_usage_totals, "estimated_cost_usd": round(total_cost, 4)}


def reset_usage() -> None:
    _usage_totals["input_tokens"] = 0
    _usage_totals["output_tokens"] = 0
    _usage_totals["calls"] = 0
    _usage_totals["by_model"] = {}


# ── Grounding constraint for generation prompts ───────────────────────────────

_GROUNDING_RULES = """\
CRITICAL GROUNDING RULES — follow these before writing any fact:

1. Only assert facts that are directly present in the analysis input provided.
2. If a fact cannot be verified from the analysis input, write exactly:
   "Not determinable from source"
   Do not infer. Do not make reasonable assumptions. Do not write what is "likely" or "probably" true.
3. Commands (build, test, run, install) MUST come from the verified_facts dict in the analysis input.
   Use these confidence rules:
   - confidence=high: state the value as fact (e.g. "pytest")
   - confidence=inferred: state as "detected as likely: <value> — verify before use"
   - confidence=not_found: write "Not determinable from source" — NEVER invent a command
   Do NOT construct commands from framework knowledge (e.g. do not write "pytest -q --cov=app"
   unless this exact string appears in the analysis input or verified_facts).
4. File paths must come from the file_tree in the analysis input.
   Do not invent paths that seem plausible.
5. Domain concepts must come from the source code analysis.
   Do not describe what the domain concepts "typically" mean.
   If domain concepts cannot be extracted from the source: write
   "Not determinable from source — fill in agent-context.json static.domain_concepts after reviewing your codebase"
6. Python version, framework version, and tool versions must come from verified_facts.python_version.
   If confidence=not_found: write "Not determinable from source"
7. For restricted_write_paths: use verified_facts.restricted_paths if confidence=high or inferred.
   If confidence=not_found: write "Not determinable from source — fill in agent-context.json static.restricted_write_paths after reviewing your repo"
   Do NOT infer which paths should be restricted from framework conventions.
8. For directory structure: list ONLY directories and files present in the file_tree from the analysis input.
   Do NOT invent plausible directories (src/, tests/, docs/, etc.) that are not in the file_tree.

Violating these rules produces context files that hallucinate facts and make AI agents less reliable, not more.
The goal is grounded accuracy, not completeness.\
"""


# ── LiteLLM call with retry ───────────────────────────────────────────────────


def _call(
    model: str,
    prompt: str,
    max_tokens: int = 3000,
) -> str:
    try:
        import litellm
    except ImportError:
        raise ImportError("litellm not installed. Run: pip install 'agent-ready[ai]'")

    last_error = None
    for attempt in range(5):
        try:
            response = litellm.completion(
                model=model,
                max_tokens=max_tokens,
                messages=[{"role": "user", "content": prompt}],
            )
            if hasattr(response, "usage") and response.usage is not None:
                if model not in _usage_totals["by_model"]:
                    _usage_totals["by_model"][model] = {"input": 0, "output": 0}
                in_toks = (
                    getattr(response.usage, "input_tokens", None)
                    or getattr(response.usage, "prompt_tokens", 0)
                    or 0
                )
                out_toks = (
                    getattr(response.usage, "output_tokens", None)
                    or getattr(response.usage, "completion_tokens", 0)
                    or 0
                )
                _usage_totals["input_tokens"] += in_toks
                _usage_totals["output_tokens"] += out_toks
                _usage_totals["calls"] += 1
                _usage_totals["by_model"][model]["input"] += in_toks
                _usage_totals["by_model"][model]["output"] += out_toks
            return response.choices[0].message.content.strip()
        except Exception as e:
            err_str = str(e).lower()
            if any(
                x in err_str
                for x in ["529", "overloaded", "service unavailable", "rate limit", "429"]
            ):
                last_error = e
                if attempt < 4:
                    wait = (60 * (attempt + 1)) + random.uniform(0, 10)
                    print(
                        f"  ⚠️  API overloaded, retrying in {int(wait)}s... (attempt {attempt + 1}/5)"
                    )
                    time.sleep(wait)
                else:
                    raise last_error
            else:
                raise
    raise last_error


def _analysis_block(analysis: dict[str, Any]) -> str:
    return json.dumps(analysis, indent=2)


def _compact_analysis_for_prompt(analysis: dict[str, Any]) -> str:
    """Extract only the fields needed for skill/hook generation to avoid token bloat."""
    compact = {
        "primary_language": analysis.get("primary_language"),
        "frameworks": analysis.get("frameworks", []),
        "build_system": analysis.get("build_system"),
        "test_command": analysis.get("test_command"),
        "build_command": analysis.get("build_command"),
        "install_command": analysis.get("install_command"),
        "run_command": analysis.get("run_command"),
        "test_framework": analysis.get("test_framework"),
        "test_directory": analysis.get("test_directory"),
        "entry_point": analysis.get("entry_point"),
        "restricted_write_paths": analysis.get("restricted_write_paths", []),
        "potential_pitfalls": analysis.get("potential_pitfalls", []),
        "verified_facts": analysis.get("verified_facts", {}),
    }
    return json.dumps(compact, indent=2)


def _pitfalls_block(analysis: dict[str, Any]) -> str:
    pitfalls = analysis.get("potential_pitfalls", [])
    if not pitfalls:
        return "No pitfalls detected."
    return "\n".join(f"{i + 1}. {p}" for i, p in enumerate(pitfalls))


# ── agent-context.json ────────────────────────────────────────────────────────


def build_agent_context(
    analysis: dict[str, Any],
    existing_static: dict[str, Any] | None = None,
) -> str:
    # Use "TODO: add tests" when analyser found no test command, so agents don't fabricate test setup
    raw_test_cmd = analysis.get("test_command", "")
    test_command = (
        raw_test_cmd
        if raw_test_cmd and raw_test_cmd != "TODO: verify"
        else "TODO: no test suite detected — add tests first"
    )

    static = existing_static or {
        "project_name": analysis.get("project_name") or "",
        "description": analysis.get("description") or "",
        "primary_language": analysis.get("primary_language") or "",
        "runtime_version": analysis.get("runtime_version") or None,
        "frameworks": analysis.get("frameworks") or [],
        "entry_point": analysis.get("entry_point") or None,
        "test_command": test_command,
        "restricted_write_paths": analysis.get("restricted_write_paths") or [],
        "environment_variables": analysis.get("environment_variables") or [],
        "domain_concepts": [
            f"{c['term']}: {c['definition']}" for c in analysis.get("domain_concepts") or []
        ],
    }

    dynamic = {
        "last_scanned": datetime.now(timezone.utc).isoformat(),
        "secondary_languages": analysis.get("secondary_languages", []),
        "build_system": analysis.get("build_system", ""),
        "build_command": analysis.get("build_command", ""),
        "install_command": analysis.get("install_command", ""),
        "run_command": analysis.get("run_command", ""),
        "test_framework": analysis.get("test_framework", ""),
        "test_directory": analysis.get("test_directory", ""),
        "source_directories": analysis.get("source_directories", []),
        "module_layout": analysis.get("module_layout", {}),
        "architecture_summary": analysis.get("architecture_summary", ""),
        "key_components": analysis.get("key_components", []),
        "agent_safe_operations": analysis.get("agent_safe_operations", []),
        "agent_forbidden_operations": analysis.get("agent_forbidden_operations", []),
        "potential_pitfalls": analysis.get("potential_pitfalls", []),
        "conventions": {
            "naming": analysis.get("naming_convention", ""),
            "structure": analysis.get("structure_type", ""),
        },
        "has_ci": analysis.get("has_ci", False),
        "has_openapi": analysis.get("has_openapi", False),
    }

    return json.dumps({"static": static, "dynamic": dynamic}, indent=2)


# ── AGENTS.md ─────────────────────────────────────────────────────────────────


def generate_agents_md(model: str, analysis: dict[str, Any]) -> str:
    return _call(
        model,
        f"""\
Generate an AGENTS.md file for this repository.

AGENTS.md is the operating contract for GitHub Copilot and OpenAI agents.
Start the file with this exact header on line 1:
{GENERATION_HEADER}

Repository analysis (derived from reading the actual code):
{_analysis_block(analysis)}

Write the following sections with SPECIFIC content — reference actual file paths,
class names, commands, and patterns found in this codebase. No generic advice.
If information is not in the analysis input, write "Not determinable from source" rather than inventing it.

{_GROUNDING_RULES}

1. ## Project Overview
   Name, what it actually does, language/framework/build tool.

2. ## Commands
   The exact verified commands — install, build, test, run, lint.

3. ## Safe Operations
   Specific things an agent IS permitted to do in this codebase.

4. ## Forbidden Operations
   Specific things an agent MUST NEVER do.
   Reference actual restricted_write_paths by name.

5. ## Domain Glossary
   Every term from domain_concepts, defined for zero-context readers.

6. ## Key Components
   Each entry from key_components: name, path, and responsibility.

7. ## Potential Pitfalls
   THIS SECTION IS CRITICAL. Write every item below verbatim as a warning.
   Do NOT summarise, generalise, or skip any item.

   Pitfalls found in this codebase:
{_pitfalls_block(analysis)}

   For each pitfall: what the agent will try to do, why it breaks things, what to do instead.

Write as if a senior engineer on this team authored it for an AI agent joining today.\
""",
    )


# ── CLAUDE.md ─────────────────────────────────────────────────────────────────


def generate_claude_md(model: str, analysis: dict[str, Any]) -> str:
    expected_skills = detect_skills(analysis)
    if expected_skills:
        skill_lines = "\n".join(
            f"   - `skills/{name}.md` — {_SKILL_DESCRIPTIONS.get(name, name)}"
            for name in expected_skills
        )
        skills_section = f"""

8. ## Available Skills
   Slash-command skill definitions generated for this repo. Each file is a
   self-contained instruction set grounded in the commands above.
{skill_lines}"""
    else:
        skills_section = ""

    return _call(
        model,
        f"""\
Generate a CLAUDE.md file for this repository.

CLAUDE.md is auto-loaded by Claude Code at the start of every session.
Start the file with this exact header on line 1:
{GENERATION_HEADER}

Repository analysis (derived from reading the actual code):
{_analysis_block(analysis)}

Write the following sections as DIRECT INSTRUCTIONS.
Every rule must reference actual file paths, class names, or patterns.
No generic software engineering advice. If information is not in the analysis input,
write "Not determinable from source" rather than inventing it.

{_GROUNDING_RULES}

1. ## Critical Commands
   Use ONLY these commands — never invent alternatives:
   - Install:  {analysis.get("install_command", "see analysis")}
   - Build:    {analysis.get("build_command", "see analysis")}
   - Test:     {analysis.get("test_command", "see analysis")}
   - Run:      {analysis.get("run_command", "see analysis")}

2. ## Always Do
   6–8 specific rules for THIS codebase.

3. ## Never Do
   6–8 prohibitions referencing restricted_write_paths and agent_forbidden_operations.

4. ## Architecture Notes
   3–4 most important design decisions to understand.

5. ## Domain Context
   Key concepts for understanding the business logic.

6. ## Known Pitfalls — Read Before Writing Any Code
   THIS SECTION IS CRITICAL. Copy every pitfall below VERBATIM.
   Do NOT add generic advice. Do NOT skip any item.

   Pitfalls found in this codebase:
{_pitfalls_block(analysis)}

7. ## After Every Change
   Specific checklist including the test command.
{skills_section}\
""",
    )


