# ── mcp.json ──────────────────────────────────────────────────────────────────


def generate_mcp_json(analysis: dict[str, Any]) -> str:
    project_name = analysis.get("project_name", "project").lower().replace(" ", "-")
    env_vars = {var: f"${{{var}}}" for var in analysis.get("environment_variables", [])[:5]}

    mcp = {
        "_comment": GENERATION_HEADER,
        "mcpServers": {
            f"{project_name}-agent-ready": {
                "command": "agent-ready-mcp",
                "args": [],
                "env": env_vars,
                "_note": (
                    "Exposes transform/score/evaluate/review_pr as MCP tools. "
                    "Install agent-ready to use: pip install agent-ready[ai]"
                ),
            }
        },
    }
    return json.dumps(mcp, indent=2)


# ── tools/refresh_context.py ─────────────────────────────────────────────────


def build_refresh_context_script(analysis: dict[str, Any]) -> str:
    """Generate a standalone tools/refresh_context.py script for the target repo.

    Running `python tools/refresh_context.py` from the repo root re-runs the
    AgentReady transformer in context-only mode, updating agent-context.json
    without touching the other generated files.
    """
    project = analysis.get("project_name", "this project")
    provider = analysis.get("_provider", "anthropic")
    return f"""\
#!/usr/bin/env python3
\"\"\"
Refresh agent-context.json for {project}.

Run this script from the repo root whenever the codebase changes significantly
(new modules, entry-point changes, new environment variables, etc.) to keep the
AI agent context up to date.

Usage:
    python tools/refresh_context.py [--provider PROVIDER] [--dry-run]

Requirements:
    pip install agent-ready[ai]
    export ANTHROPIC_API_KEY=...   # or whichever provider you use
\"\"\"
from __future__ import annotations

import argparse
import subprocess
import sys
from pathlib import Path

REPO_ROOT = Path(__file__).parent.parent
DEFAULT_PROVIDER = "{provider}"


def main() -> None:
    parser = argparse.ArgumentParser(description="Refresh agent-context.json")
    parser.add_argument(
        "--provider",
        default=DEFAULT_PROVIDER,
        help=f"LLM provider (default: {{DEFAULT_PROVIDER}})",
    )
    parser.add_argument(
        "--dry-run",
        action="store_true",
        help="Show what would change without writing files",
    )
    args = parser.parse_args()

    cmd = [
        sys.executable, "-m", "agent_ready.cli",
        "--target", str(REPO_ROOT),
        "--provider", args.provider,
        "--only", "context",
    ]
    if args.dry_run:
        cmd.append("--dry-run")

    print(f"🔄 Refreshing agent-context.json for {project}...")
    print(f"   Provider : {{args.provider}}")
    print(f"   Target   : {{REPO_ROOT}}")
    if args.dry_run:
        print("   Mode     : dry-run (no files written)")
    print()

    result = subprocess.run(cmd, cwd=REPO_ROOT)
    sys.exit(result.returncode)


if __name__ == "__main__":
    main()
"""


# ── .github/CODEOWNERS ───────────────────────────────────────────────────────


def build_codeowners(analysis: dict[str, Any]) -> str:
    """Generate .github/CODEOWNERS so AgentReady-generated files require human review.

    All generated context and workflow files are owned by '*' (the default owners
    defined in the repo/org settings). Adjust as needed — this is safe to edit.
    """
    restricted = analysis.get("restricted_write_paths", [])

    lines = [
        "# Auto-generated by AgentReady — safe to edit.",
        "# Docs: https://docs.github.com/en/repositories/managing-your-repositorys-settings-and-features/customizing-your-repository/about-code-owners",
        "",
        "# AgentReady-generated context and workflow files require explicit human approval.",
        "# Replace '*' with your team handle, e.g. @myorg/platform-team",
        "agent-context.json        *",
        "AGENTS.md                 *",
        "CLAUDE.md                 *",
        ".cursorrules              *",
        "system_prompt.md          *",
        "mcp.json                  *",
        "AGENTIC_EVAL.md           *",
        "memory/                   *",
        "skills/                   *",
        "hooks/                    *",
        ".github/copilot-instructions.md  *",
        ".github/workflows/        *",
        "",
    ]

    if restricted:
        lines.append("# Restricted paths identified by AgentReady analysis")
        for path in restricted:
            clean = path.rstrip("/")
            if not clean.endswith("/") and "." not in clean.split("/")[-1]:
                clean += "/"
            lines.append(f"{clean}  *")
        lines.append("")

    return "\n".join(lines)


