def _is_rest_api(analysis: dict[str, Any]) -> bool:
    frameworks = {f.lower() for f in analysis.get("frameworks", [])}
    return bool(frameworks & _REST_FRAMEWORKS)


def build_openapi_stub(analysis: dict[str, Any]) -> str:
    """Generate a minimal openapi.yaml stub for REST API repositories.

    This is intentionally sparse — it establishes the file so the eval scorer
    awards the +5 openapi points, and gives developers a starting point to fill in.
    """
    project = analysis.get("project_name", "API")
    desc = analysis.get("description", f"REST API for {project}")
    lang = analysis.get("primary_language", "python").lower()
    frameworks = analysis.get("frameworks", [])
    framework = frameworks[0] if frameworks else "unknown"

    stub = {
        "openapi": "3.1.0",
        "info": {
            "title": project,
            "description": (
                f"{desc}\n\n"
                f"**Auto-generated stub** — fill in paths, schemas, and security.\n"
                f"Stack: {lang} / {framework}"
            ),
            "version": "0.1.0",
        },
        "paths": {
            "/health": {
                "get": {
                    "summary": "Health check",
                    "operationId": "health_check",
                    "responses": {
                        "200": {
                            "description": "Service is healthy",
                            "content": {
                                "application/json": {
                                    "schema": {
                                        "type": "object",
                                        "properties": {"status": {"type": "string"}},
                                    }
                                }
                            },
                        }
                    },
                }
            }
        },
        "components": {"schemas": {}, "securitySchemes": {}},
    }

    import yaml

    header = (
        "# Auto-generated stub by AgentReady — fill in your actual paths and schemas.\n"
        "# Run: npx @redocly/cli lint openapi.yaml   to validate.\n"
    )
    return header + yaml.dump(stub, default_flow_style=False, sort_keys=False)


# ── .agent-ready/custom_questions.json ───────────────────────────────────────


def build_custom_questions_starter(analysis: dict[str, Any]) -> str:
    """Generate an example custom_questions.json so repo owners discover the hook.

    AgentReady eval v2 auto-loads this file when running evaluations.
    Users can add project-specific questions that the golden base set doesn't cover.
    """
    project = analysis.get("project_name", "this project")
    lang = analysis.get("primary_language", "python").lower()
    entry = analysis.get("entry_point", "main")

    example_questions = [
        {
            "_comment": (
                "Add project-specific eval questions here. "
                "AgentReady will merge these with the golden base set on every eval run. "
                "Remove the leading underscore from 'id' etc. to activate a question."
            ),
            "_id": f"custom_{lang}_001",
            "_version": "1.0",
            "_category": "commands",
            "_difficulty": "medium",
            "_prompt": f"How do you start {project} in development mode?",
            "_pass_threshold": 7,
            "_ground_truth_extraction": {
                "method": "static_then_llm",
                "static_sources": [
                    {
                        "type": "jsonpath",
                        "file": "agent-context.json",
                        "path": "$.static.run_command",
                    },
                ],
                "llm_prompt": f"What is the command to start {project} locally? Read {entry}.",
            },
            "_evaluation_criteria": f"Must include the exact run command for {project}.",
        },
        {
            "_comment": "Second example — domain-specific question",
            "_id": "custom_domain_001",
            "_version": "1.0",
            "_category": "domain",
            "_difficulty": "hard",
            "_prompt": "What happens to data when the application restarts?",
            "_pass_threshold": 8,
            "_ground_truth_extraction": {
                "method": "llm",
                "llm_prompt": "Does this application persist data across restarts? Read all source files carefully.",
            },
            "_evaluation_criteria": "Must accurately describe the persistence (or lack of) behaviour.",
        },
    ]

    return json.dumps(
        {
            "_instructions": (
                "Remove the leading underscore from field names (e.g. '_id' → 'id') "
                "to activate a question. All active questions are merged with the "
                "AgentReady golden base set on every evaluation run."
            ),
            "questions": example_questions,
        },
        indent=2,
    )


# ── .cursorrules ──────────────────────────────────────────────────────────────


def build_cursorrules(analysis: dict[str, Any]) -> str:
    """Generate a .cursorrules file from analysis data.

    Deterministic — no LLM call. Same input always produces the same output.
    Commands are taken verbatim from analysis; missing values get explicit
    'Not determinable from source' placeholders rather than invented content.
    """
    name = analysis.get("project_name", "this project")
    desc = analysis.get("description", "")
    lang = analysis.get("primary_language", "")
    frameworks = analysis.get("frameworks", [])
    framework = ", ".join(frameworks) if frameworks else "none detected"
    build_sys = analysis.get("build_system", "")

    def _cmd(key: str) -> str:
        val = analysis.get(key, "")
        if val and val not in ("TODO: verify", ""):
            return val
        return "Not determinable from source"

    naming = analysis.get("naming_convention", "")
    structure = analysis.get("structure_type", "")
    source_dirs = analysis.get("source_directories", [])
    test_dir = analysis.get("test_directory", "")
    entry = analysis.get("entry_point", "")
    restricted = analysis.get("restricted_write_paths", [])
    domain_concepts = analysis.get("domain_concepts", [])

    lines = [f"# {name}", ""]

    lines += [
        "## Project overview",
        desc or "<!-- Fill in: what this project does for its end users -->",
        "",
    ]

    lines += [
        "## Language and framework",
        f"- Primary language: {lang or 'unknown'}",
        f"- Framework: {framework}",
        f"- Build system: {build_sys or 'unknown'}",
        "",
    ]

    lines += [
        "## Critical commands",
        f"- Install: {_cmd('install_command')}",
        f"- Build: {_cmd('build_command')}",
        f"- Test: {_cmd('test_command')}",
        f"- Run locally: {_cmd('run_command')}",
        "",
    ]

    conventions_parts = []
    if naming:
        conventions_parts.append(f"Naming: {naming}")
    if structure:
        conventions_parts.append(f"Structure: {structure}")
    if source_dirs:
        conventions_parts.append(f"Source directories: {', '.join(source_dirs)}")
    lines += [
        "## Code conventions",
        "\n".join(conventions_parts)
        if conventions_parts
        else "<!-- Fill in: naming, file structure, patterns -->",
        "",
    ]

    dir_lines = []
    if entry:
        dir_lines.append(f"- Entry point: {entry}")
    if test_dir:
        dir_lines.append(f"- Tests: {test_dir}")
    lines += [
        "## Files and directories",
        "\n".join(dir_lines) if dir_lines else "<!-- Fill in: key file locations -->",
        "",
    ]

    lines += [
        "## Do not modify",
        "\n".join(f"- {p}" for p in restricted)
        if restricted
        else "Not determinable from source — fill in agent-context.json static.restricted_write_paths",
        "",
    ]

    concept_lines = [
        f"- {c['term']}: {c['definition']}" for c in domain_concepts if isinstance(c, dict)
    ]
    lines += [
        "## Domain concepts",
        "\n".join(concept_lines)
        if concept_lines
        else "Not determinable from source — fill in agent-context.json static.domain_concepts",
        "",
    ]

    return "\n".join(lines)


# ── skills/ ───────────────────────────────────────────────────────────────────

_LINTERS = {
    "ruff",
    "eslint",
    "checkstyle",
    "pylint",
    "flake8",
    "rubocop",
    "golangci-lint",
    "clippy",
}
_MIGRATION_FRAMEWORKS = {"flyway", "alembic", "liquibase", "migrate", "knex"}
_DOCKER_SIGNALS = {"docker", "docker-compose"}
_PACKAGE_MANAGERS = {"pip", "npm", "yarn", "gradle", "maven", "cargo", "bundler", "go"}


def detect_skills(analysis: dict[str, Any]) -> list[str]:
    """Return list of skill names to generate based on repo signals."""
    skills: list[str] = []

    # Always generate these two
    skills.append("run-tests")
    skills.append("build")

    raw_frameworks = analysis.get("frameworks") or []
    frameworks_lower = {f.lower() for f in raw_frameworks if isinstance(f, str)}
    raw_build_sys = analysis.get("build_system", "")
    build_sys = str(raw_build_sys).lower() if raw_build_sys else ""

    # Linter
    if frameworks_lower & _LINTERS:
        skills.append("lint")

    # Docker — check specific config file names, not broad substring matching
    docker_config_files = {"docker-compose.yml", "docker-compose.yaml", "Dockerfile"}
    file_tree = set(analysis.get("file_tree") or [])
    config_file_keys = set((analysis.get("config_files") or {}).keys())
    has_docker = bool(
        docker_config_files & file_tree
        or docker_config_files & config_file_keys
        or {"docker", "docker-compose"} & frameworks_lower
    )
    if has_docker:
        skills.append("start-local")

    # Migration framework
    if frameworks_lower & _MIGRATION_FRAMEWORKS:
        skills.append("run-migrations")

    # CI
    if analysis.get("has_ci", False):
        skills.append("run-ci")

    # OpenAPI
    if analysis.get("has_openapi", False):
        skills.append("generate-api-docs")

    # Package manager
    if build_sys in _PACKAGE_MANAGERS:
        skills.append("add-dependency")

    # Deduplicate while preserving order
    seen: set[str] = set()
    result: list[str] = []
    for s in skills:
        if s not in seen:
            seen.add(s)
            result.append(s)
    return result


_SKILL_DESCRIPTIONS = {
    "run-tests": "Run the full test suite with project-configured settings.",
    "build": "Build the project artifacts.",
    "lint": "Run the linter and fix reported issues.",
    "start-local": "Start the application locally using Docker.",
    "run-migrations": "Apply pending database migrations.",
    "run-ci": "Trigger or simulate the CI pipeline.",
    "generate-api-docs": "Generate or update API documentation from the OpenAPI spec.",
    "add-dependency": "Add a new dependency to the project.",
}


def generate_skill_file(model: str, skill_name: str, analysis: dict[str, Any]) -> str:
    desc = _SKILL_DESCRIPTIONS.get(skill_name, f"Execute the {skill_name} workflow.")
    return _call(
        model,
        f"""\
Generate a skill file named '{skill_name}' for this repository.

A skill file is a self-contained instruction set for a specific repo action,
used by Claude Code as a slash-command reference.

Repository analysis:
{_compact_analysis_for_prompt(analysis)}

The skill name is: {skill_name}
The skill description is: {desc}

{_GROUNDING_RULES}

Write the file using EXACTLY this structure — no deviations:

---
name: {skill_name}
description: {desc}
---

## When to use this skill

<One sentence trigger condition.>

## Steps

1. <First step — use the EXACT command from the analysis above if available>
2. <Second step>
3. <Validation step — how to confirm success>

## Expected output

<What a successful run looks like. Be specific.>

## Common failures

- **<Failure condition>**: <How to recover>
- **<Failure condition>**: <How to recover>

RULES:
- Commands MUST come from the analysis JSON above (test_command, build_command, install_command, run_command, etc.).
- If a command cannot be determined, write: "Command not determinable from source — check your project's documentation."
- Do NOT invent commands. Do NOT use generic placeholders like "npm run build" unless that is the actual command in the analysis.
- Omit the "## Notes" section unless there is a specific project caveat from the analysis worth flagging.
- Output only the file content — no preamble, no explanation.\
""",
        max_tokens=1000,
    )


# ── hooks/ ────────────────────────────────────────────────────────────────────


def detect_hooks(analysis: dict[str, Any]) -> list[str]:
    """Return list of hook names to generate based on repo signals."""
    hooks: list[str] = ["session-start", "pre-tool-call"]

    test_cmd = analysis.get("test_command", "")
    if test_cmd and test_cmd not in (
        "TODO: verify",
        "TODO: no test suite detected — add tests first",
    ):
        hooks.append("post-test")

    frameworks_lower = {f.lower() for f in analysis.get("frameworks", [])}
    if frameworks_lower & _LINTERS:
        hooks.append("pre-commit")

    return hooks


_HOOK_TRIGGERS = {
    "session-start": "At the start of every Claude Code session",
    "pre-tool-call": "Before any tool call that writes files",
    "post-test": "After running the test command",
    "pre-commit": "Before a git commit",
}


def generate_hook_file(
    model: str,
    hook_name: str,
    analysis: dict[str, Any],
    generated_files: set[str] | None = None,
) -> str:
    trigger = _HOOK_TRIGGERS.get(hook_name, f"When {hook_name} event fires")
    generated_files = generated_files or set()

    context_note = (
        "Load current state from agent-context.json"
        if "agent-context.json" in generated_files
        else "agent-context.json not yet generated — run AgentReady first to generate it"
    )
    memory_note = (
        "Check memory/schema.md for session state contract"
        if "memory/schema.md" in generated_files
        else "memory/schema.md not yet generated — run AgentReady first to generate it"
    )

    return _call(
        model,
        f"""\
Generate a hook file named '{hook_name}' for this repository.

A hook file defines actions Claude Code takes at a specific lifecycle point.

Repository analysis:
{_compact_analysis_for_prompt(analysis)}

The hook name is: {hook_name}
The trigger is: {trigger}

Context availability:
- agent-context.json: {context_note}
- memory/schema.md: {memory_note}

{_GROUNDING_RULES}

Write the file using EXACTLY this structure — no deviations:

---
name: {hook_name}
trigger: {trigger}
---

## Purpose

<One sentence describing what this hook does and why it exists for this specific repo.>

## Actions

1. <Specific action grounded in this repo's configuration>
2. <Second action>

## Context loaded

<What information this hook makes available to the agent.>

## Skipped when

<Conditions under which this hook should not execute.>

RULES:
- All actions must be grounded in this specific repo's configuration (commands, paths, restricted_write_paths).
- Use exact commands from the analysis where relevant.
- For 'pre-tool-call': always reference restricted_write_paths from the analysis.
- For 'post-test': always reference the test_command from the analysis.
- For 'pre-commit': always reference the linter command from the analysis.
- Include "AGENT_SKIP_HOOKS=true environment variable is set" as one skipped-when condition.
- Only reference agent-context.json or memory/schema.md if the context availability above confirms they exist.
- Output only the file content — no preamble, no explanation.\
""",
        max_tokens=800,
    )


# ── .github/dependabot.yml ────────────────────────────────────────────────────


_ECOSYSTEM_MAP: dict[str, str] = {
    # build_system → dependabot package-ecosystem
    "npm": "npm",
    "yarn": "npm",
    "pip": "pip",
    "cargo": "cargo",
    "maven": "maven",
    "gradle": "gradle",
    "bundler": "bundler",
    "go": "gomod",
    # primary_language fallbacks
    "python": "pip",
    "javascript": "npm",
    "typescript": "npm",
    "rust": "cargo",
    "java": "maven",
    "ruby": "bundler",
}


def build_dependabot_yml(analysis: dict[str, Any]) -> str:
    """Generate .github/dependabot.yml for automatic dependency updates."""
    build_sys = analysis.get("build_system", "unknown").lower()
    lang = analysis.get("primary_language", "").lower()
    ecosystem = _ECOSYSTEM_MAP.get(build_sys) or _ECOSYSTEM_MAP.get(lang) or "pip"

    updates = [
        {
            "package-ecosystem": ecosystem,
            "directory": "/",
            "schedule": {"interval": "weekly"},
            "groups": {"all-dependencies": {"patterns": ["*"]}},
        },
        # Always keep GitHub Actions up to date
        {
            "package-ecosystem": "github-actions",
            "directory": "/",
            "schedule": {"interval": "monthly"},
            "groups": {"github-actions": {"patterns": ["*"]}},
        },
    ]

    import yaml  # pyyaml is a transitive dep of litellm

    body = yaml.dump({"version": 2, "updates": updates}, default_flow_style=False, sort_keys=False)
    return f"# Auto-generated by AgentReady — safe to edit\n{body}"


# ── Orchestrator ──────────────────────────────────────────────────────────────


class LLMGenerator:
    def __init__(
        self,
        target: Path,
        analysis: dict[str, Any],
        generation_model: str,
        dry_run: bool = False,
        force: bool = False,
        quiet: bool = False,
    ):
        self.target = target
        self.analysis = analysis
        self.model = generation_model
        self.dry_run = dry_run
        self.force = force
        self.quiet = quiet
        self.generated: list[tuple[str, str]] = []

    def generate_all(self) -> list[tuple[str, str]]:
        self._agent_context()
        self._agents_md()
        self._claude_md()
        self._cursorrules()
        self._copilot_instructions()
        self._system_prompt()
        self._mcp_json()
        self._memory_schema()
        self._skills()
        self._hooks()
        self._refresh_context_script()
        self._dependabot_yml()
        self._custom_questions_starter()
        self._openapi_stub()
        self._codeowners()
        return self.generated

    def generate_only(self, category: str) -> list[tuple[str, str]]:
        dispatch = {
            "agents": lambda: (
                self._agents_md(),
                self._claude_md(),
                self._copilot_instructions(),
                self._system_prompt(),
            ),
            "context": lambda: (
                self._agent_context(),
                self._refresh_context_script(),
            ),
            "memory": self._memory_schema,
        }
        fn = dispatch.get(category)
        if fn is None:
            raise ValueError(f"Unknown category: {category!r}")
        fn()
        return self.generated

    def _agent_context(self) -> None:
        existing_static: dict[str, Any] | None = None
        ctx_path = self.target / "agent-context.json"
        if ctx_path.exists():
            try:
                existing = json.loads(ctx_path.read_text())
                existing_static = existing.get("static")
                if not self.quiet and existing_static:
                    print("  ℹ️  Existing static section found — preserving it")
            except Exception:
                pass
        content = build_agent_context(self.analysis, existing_static)
        self._write("agent-context.json", content, always_overwrite=True)

    def _agents_md(self) -> None:
        if not self.quiet:
            print("  ✍️  Generating AGENTS.md...")
        self._write("AGENTS.md", generate_agents_md(self.model, self.analysis))

    def _claude_md(self) -> None:
        if not self.quiet:
            print("  ✍️  Generating CLAUDE.md...")
        self._write("CLAUDE.md", generate_claude_md(self.model, self.analysis))

    def _cursorrules(self) -> None:
        self._write(".cursorrules", build_cursorrules(self.analysis))

    def _skills(self) -> None:
        skill_names = detect_skills(self.analysis)
        for skill_name in skill_names:
            if not self.quiet:
                print(f"  ✍️  Generating skills/{skill_name}.md...")
            try:
                content = generate_skill_file(self.model, skill_name, self.analysis)
                self._write(f"skills/{skill_name}.md", content)
            except Exception as e:
                if not self.quiet:
                    print(f"  ⚠️  Failed to generate skills/{skill_name}.md: {e}. Skipping.")
                self.generated.append((f"skills/{skill_name}.md", "⚠️  Skipped (error)"))

    def _hooks(self) -> None:
        hook_names = detect_hooks(self.analysis)
        generated_paths = {path for path, _ in self.generated}
        for hook_name in hook_names:
            if not self.quiet:
                print(f"  ✍️  Generating hooks/{hook_name}.md...")
            try:
                content = generate_hook_file(self.model, hook_name, self.analysis, generated_paths)
                self._write(f"hooks/{hook_name}.md", content)
            except Exception as e:
                if not self.quiet:
                    print(f"  ⚠️  Failed to generate hooks/{hook_name}.md: {e}. Skipping.")
                self.generated.append((f"hooks/{hook_name}.md", "⚠️  Skipped (error)"))

    def _copilot_instructions(self) -> None:
        if not self.quiet:
            print("  ✍️  Generating .github/copilot-instructions.md...")
        self._write(
            ".github/copilot-instructions.md",
            generate_copilot_instructions(self.model, self.analysis),
        )

    def _system_prompt(self) -> None:
        if not self.quiet:
            print("  ✍️  Generating system_prompt.md...")
        self._write("system_prompt.md", generate_system_prompt(self.model, self.analysis))

    def _mcp_json(self) -> None:
        self._write("mcp.json", generate_mcp_json(self.analysis))

    def _memory_schema(self) -> None:
        if not self.quiet:
            print("  ✍️  Generating memory/schema.md...")
        self._write("memory/schema.md", generate_memory_schema(self.model, self.analysis))

    def _refresh_context_script(self) -> None:
        self._write(
            "tools/refresh_context.py",
            build_refresh_context_script(self.analysis),
        )

    def _dependabot_yml(self) -> None:
        self._write(
            ".github/dependabot.yml",
            build_dependabot_yml(self.analysis),
        )

    def _custom_questions_starter(self) -> None:
        self._write(
            ".agent-ready/custom_questions.json",
            build_custom_questions_starter(self.analysis),
        )

    def _openapi_stub(self) -> None:
        # Only generate for REST API repos that don't already have an OpenAPI spec
        if not self.analysis.get("has_openapi", False) and _is_rest_api(self.analysis):
            self._write("openapi.yaml", build_openapi_stub(self.analysis))

    def _codeowners(self) -> None:
        self._write(".github/CODEOWNERS", build_codeowners(self.analysis))

    def _write(self, rel_path: str, content: str, always_overwrite: bool = False) -> None:
        full_path = self.target / rel_path
        already_exists = full_path.exists()

        if already_exists and not self.force and not always_overwrite:
            if not self.quiet:
                print(f"  ⏭️  {rel_path} (exists — use --force to overwrite)")
            self.generated.append((rel_path, "⏭️  Skipped"))
        elif self.dry_run:
            if not self.quiet:
                print(f"  📝 [dry-run] {rel_path}")
            self.generated.append((rel_path, "📝 (dry-run)"))
        else:
            full_path.parent.mkdir(parents=True, exist_ok=True)
            full_path.write_text(content, encoding="utf-8")
            status = "🔄 Updated" if already_exists else "✅ Created"
            if not self.quiet:
                print(f"  {status[:2]} {rel_path}")
            self.generated.append((rel_path, status))
